export function tokenisePath(key){if(typeof key==="string"){if(key.includes("/")){key=key.split("/")}else{key=key.split(".")}}return key}export function simplifyPathTokens(path){let tokens=tokenisePath(path);const slice=tokens.slice(-2);if(slice[0]==="dca"){const old=[...tokens];tokens=[...tokens.slice(0,-2),...slice.slice(1)];logger.debug({oldPath:old.join("."),newPath:tokens.join(".")},"Simplified path token")}return tokens}